// nodes/transformNode.js
import { useState } from 'react';
import { BaseNode, fieldStyle } from './BaseNode';
import { useStore } from '../store';

export const TransformNode = ({ id, data }) => {
  const updateNodeField = useStore((s) => s.updateNodeField);
  const [code, setCode] = useState(data?.code ?? '// transform(input) =>\nreturn input.toUpperCase();');
  const [language, setLanguage] = useState(data?.language ?? 'javascript');

  return (
    <BaseNode
      id={id}
      title="Transform"
      icon="⚙️"
      accentColor="#c084fc"
      inputs={[{ id: 'input', label: 'input' }]}
      outputs={[{ id: 'output', label: 'output' }]}
      minWidth={260}
    >
      <div style={fieldStyle.group}>
        <label style={fieldStyle.label}>Language</label>
        <select
          style={fieldStyle.select}
          value={language}
          onChange={(e) => {
            setLanguage(e.target.value);
            updateNodeField(id, 'language', e.target.value);
          }}
        >
          <option value="javascript">JavaScript</option>
          <option value="python">Python</option>
          <option value="jq">jq</option>
        </select>
      </div>
      <div style={fieldStyle.group}>
        <label style={fieldStyle.label}>Code</label>
        <textarea
          style={{
            ...fieldStyle.input,
            resize: 'vertical',
            minHeight: '70px',
            fontFamily: "'JetBrains Mono', 'Fira Code', monospace",
            fontSize: '11px',
            lineHeight: 1.5,
          }}
          value={code}
          onChange={(e) => {
            setCode(e.target.value);
            updateNodeField(id, 'code', e.target.value);
          }}
        />
      </div>
    </BaseNode>
  );
};
